// ============================================================================
// TYPES
// ============================================================================

export type PricingMode = 'CATEGORY_ABC' | 'FLAT_TIER' | 'PER_MILE'

export interface CategoryRule {
  category: 'A' | 'B' | 'C'
  price: number
}

export interface PricingTier {
  minMiles: number
  maxMiles: number
  flatPrice: number
}

export interface PricingConfig {
  id?: string
  name: string
  pricingMode: PricingMode
  baseFee: number
  insuranceFee: number
  transactionFeePct?: number
  transactionFeeFixed?: number
  feePassThrough?: boolean
  driverSharePct?: number
  tiers: PricingTier[]
  categoryRules: CategoryRule[]
  isActive?: boolean
  createdAt?: string
  updatedAt?: string
}

// ============================================================================
// VALIDATION SCHEMA
// ============================================================================

const categoryRuleSchema = z.object({
  category: z.enum(['A', 'B', 'C']),
  price: z.number().min(0, 'Price must be 0 or greater')
})

const pricingTierSchema = z.object({
  minMiles: z.number().min(0, 'Minimum miles must be 0 or greater'),
  maxMiles: z.number().min(0, 'Maximum miles must be 0 or greater'),
  flatPrice: z.number().min(0, 'Flat price must be 0 or greater')
}).refine(data => data.maxMiles > data.minMiles, {
  message: 'Maximum miles must be greater than minimum miles',
  path: ['maxMiles']
})

const pricingConfigSchema = z.object({
  id: z.string().optional(),
  name: z.string().min(1, 'Configuration name is required').max(100),
  pricingMode: z.enum(['CATEGORY_ABC', 'FLAT_TIER', 'PER_MILE']),
  baseFee: z.number().min(0, 'Base fee must be 0 or greater'),
  insuranceFee: z.number().min(0, 'Insurance fee must be 0 or greater'),
  transactionFeePct: z.number().min(0).max(100).optional(),
  transactionFeeFixed: z.number().min(0).optional(),
  feePassThrough: z.boolean().optional(),
  driverSharePct: z.number().min(0).max(100).optional(),
  tiers: z.array(pricingTierSchema),
  categoryRules: z.array(categoryRuleSchema)
}).superRefine((data, ctx) => {
  // Validation rules based on pricing mode
  if (data.pricingMode === 'CATEGORY_ABC') {
    if (data.tiers.length > 0) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: 'Tiers must be empty when using CATEGORY_ABC mode',
        path: ['tiers']
      })
    }
    if (data.categoryRules.length === 0) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: 'Category rules are required when using CATEGORY_ABC mode',
        path: ['categoryRules']
      })
    }
    // Check for all categories A, B, C
    const categories = data.categoryRules.map(r => r.category)
    const requiredCategories: ('A' | 'B' | 'C')[] = ['A', 'B', 'C']
    for (const cat of requiredCategories) {
      if (!categories.includes(cat)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: `Category ${cat} rule is required`,
          path: ['categoryRules']
        })
      }
    }
  }
  
  if (data.pricingMode === 'FLAT_TIER') {
    if (data.categoryRules.length > 0) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: 'Category rules must be empty when using FLAT_TIER mode',
        path: ['categoryRules']
      })
    }
    if (data.tiers.length === 0) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: 'At least one tier is required when using FLAT_TIER mode',
        path: ['tiers']
      })
    }
  }
  
  if (data.pricingMode === 'PER_MILE') {
    if (data.tiers.length > 0) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: 'Tiers must be empty when using PER_MILE mode',
        path: ['tiers']
      })
    }
    if (data.categoryRules.length > 0) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: 'Category rules must be empty when using PER_MILE mode',
        path: ['categoryRules']
      })
    }
  }
})

type PricingConfigFormData = z.infer<typeof pricingConfigSchema>

// ============================================================================
// API FUNCTIONS
// ============================================================================

const API_BASE_URL = '/api'

async function fetchPricingConfigs(): Promise<PricingConfig[]> {
  try {
    const response = await fetch(`${API_BASE_URL}/pricingConfigs`, {
      method: 'GET',
      headers: { 'Content-Type': 'application/json' }
    })
    if (!response.ok) throw new Error('Failed to fetch pricing configs')
    return await response.json()
  } catch (error) {
    console.error('Error fetching pricing configs:', error)
    return []
  }
}

async function fetchPricingConfigById(id: string): Promise<PricingConfig | null> {
  try {
    const response = await fetch(`${API_BASE_URL}/pricingConfigs/${id}`, {
      method: 'GET',
      headers: { 'Content-Type': 'application/json' }
    })
    if (!response.ok) throw new Error('Failed to fetch pricing config')
    return await response.json()
  } catch (error) {
    console.error('Error fetching pricing config:', error)
    return null
  }
}

async function savePricingConfig(data: PricingConfigFormData): Promise<{ success: boolean; data?: PricingConfig; error?: string }> {
  try {
    const response = await fetch(`${API_BASE_URL}/pricingConfigs`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data)
    })
    
    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}))
      throw new Error(errorData.message || 'Failed to save pricing configuration')
    }
    
    const result = await response.json()
    return { success: true, data: result }
  } catch (error: any) {
    console.error('Error saving pricing config:', error)
    return { success: false, error: error.message }
  }
}

// ============================================================================
// DEFAULT VALUES
// ============================================================================

const defaultCategoryRules: CategoryRule[] = [
  { category: 'A', price: 120 },
  { category: 'B', price: 160 },
  { category: 'C', price: 210 }
]

const defaultTiers: PricingTier[] = [
  { minMiles: 0, maxMiles: 25, flatPrice: 120 },
  { minMiles: 25.01, maxMiles: 75, flatPrice: 220 }
]

const getDefaultValues = (mode: PricingMode): Partial<PricingConfigFormData> => ({
  name: '',
  pricingMode: mode,
  baseFee: 40,
  insuranceFee: 8,
  transactionFeePct: 2.9,
  transactionFeeFixed: 3,
  feePassThrough: true,
  driverSharePct: 60,
  tiers: mode === 'FLAT_TIER' ? defaultTiers : [],
  categoryRules: mode === 'CATEGORY_ABC' ? defaultCategoryRules : []
})

